/* === stack.h (header -- public API) === */
#ifndef STACK_H
#define STACK_H

/* Opaque type: clients see only a pointer, not the internals */
typedef struct Stack Stack;

Stack *stack_create(int capacity);
void stack_push(Stack *s, int value);
int stack_pop(Stack *s);
int stack_is_empty(const Stack *s);
void stack_destroy(Stack *s);

#endif

/* === stack.c (implementation -- struct defined here) === */
/* #include "stack.h" */
#include <stdio.h>
#include <stdlib.h>

struct Stack {
    int *data;
    int top;
    int capacity;
};

Stack *stack_create(int capacity) {
    Stack *s = (Stack *)malloc(sizeof(Stack));
    if (!s) return NULL;
    s->data = (int *)malloc(sizeof(int) * capacity);
    s->top = -1;
    s->capacity = capacity;
    return s;
}

void stack_push(Stack *s, int value) {
    if (s->top < s->capacity - 1) {
        s->data[++s->top] = value;
    }
}

int stack_pop(Stack *s) {
    if (s->top >= 0) return s->data[s->top--];
    return -1; /* error value */
}

int stack_is_empty(const Stack *s) {
    return s->top == -1;
}

void stack_destroy(Stack *s) {
    if (s) {
        free(s->data);
        free(s);
    }
}

/* === main.c (client code) === */
int main(void) {
    Stack *s = stack_create(10);
    stack_push(s, 10);
    stack_push(s, 20);
    stack_push(s, 30);

    while (!stack_is_empty(s)) {
        printf("%d ", stack_pop(s)); /* 30 20 10 */
    }
    printf("\n");

    /* s->data = NULL; */  /* ERROR: struct Stack is incomplete */
    stack_destroy(s);
    return 0;
}

