#include <stdio.h>
#include <string.h>

/* Aliasing prevents optimization */
void copy_with_aliasing(int *a, int *b) {
    *a = 5;
    *b = 10;
    /* Compiler must reload *a because a and b might overlap */
    printf("a = %d\n", *a); /* Could be 5 or 10 */
}

/* WRONG: violates strict aliasing rule */
float int_bits_to_float_BAD(int i) {
    /* Accessing int memory as float is undefined behavior */
    /* return *(float *)&i; */  /* DO NOT DO THIS */
    return 0.0f; /* placeholder */
}

/* CORRECT: use memcpy for type punning (always safe) */
float int_bits_to_float_GOOD(int i) {
    float f;
    memcpy(&f, &i, sizeof(f)); /* safe type punning */
    return f;
}

/* CORRECT: use union for type punning (C99 allows this) */
float int_bits_to_float_union(int i) {
    union { int i; float f; } u;
    u.i = i;
    return u.f;
}

int main(void) {
    int x = 42;

    /* Demonstrating aliasing */
    copy_with_aliasing(&x, &x); /* a and b alias! a = 10 */

    /* char* can alias anything (exception to strict aliasing) */
    char *bytes = (char *)&x;
    printf("First byte of x: 0x%02x\n", (unsigned char)bytes[0]);

    /* Safe type punning with memcpy */
    int bits = 0x40490FDB; /* IEEE 754 for approx pi */
    float pi = int_bits_to_float_GOOD(bits);
    printf("pi approx: %f\n", pi); /* ~3.141593 */

    return 0;
}

