/* Calculator with dispatch table */
double calc_add(double a, double b) { return a + b; }
double calc_sub(double a, double b) { return a - b; }
double calc_mul(double a, double b) { return a * b; }
double calc_div(double a, double b) {
    if (b == 0.0) { printf("Error: division by zero\n"); return 0.0; }
    return a / b;
}

typedef double (*CalcOp)(double, double);

int main(void) {
    /* Dispatch table: index maps to operation */
    CalcOp ops[] = {calc_add, calc_sub, calc_mul, calc_div};
    const char *names[] = {"+", "-", "*", "/"};
    int num_ops = sizeof(ops) / sizeof(ops[0]);

    double a = 10.0, b = 3.0;
    for (int i = 0; i < num_ops; i++) {
        printf("%.1f %s %.1f = %.2f\n", a, names[i], b, ops[i](a, b));
