/* Generic find: linear search for any type */
void *generic_find(void *base, size_t count, size_t elem_size,
                   const void *target,
                   int (*compare)(const void *, const void *)) {
    for (size_t i = 0; i < count; i++) {
        void *elem = (char *)base + i * elem_size;
        if (compare(elem, target) == 0) {
