#include <stdio.h>
#include <stdlib.h>

/* Safe free macro: frees and NULLs the pointer */
#define SAFE_FREE(p) do { free(p); (p) = NULL; } while(0)

/* BAD: returns address of local variable */
/*
int *dangling_example(void) {
    int x = 42;
    return &x;   // WARNING: address of local variable
}
*/

/* GOOD: allocate on heap to return */
int *safe_example(void) {
    int *p = (int *)malloc(sizeof(int));
    if (p) *p = 42;
    return p; /* Caller must free this */
}

int main(void) {
    /* Scenario 1: Use after free */
    int *p = (int *)malloc(sizeof(int));
    *p = 100;
    printf("Before free: %d\n", *p); /* 100 */
    free(p);
    /* printf("%d\n", *p); */  /* DANGLING: undefined behavior! */
    p = NULL; /* Best practice: NULL after free */

    /* Scenario 2: Using SAFE_FREE macro */
    int *q = (int *)malloc(sizeof(int));
    *q = 200;
    SAFE_FREE(q);
    /* q is now NULL -- dereferencing will crash predictably */
    if (q == NULL) {
        printf("q is safely NULL\n");
    }

    /* Scenario 3: Safe return from function */
    int *r = safe_example();
    printf("Safe value: %d\n", *r); /* 42 */
    SAFE_FREE(r);

    return 0;
}

/*
 * Compile with AddressSanitizer to detect dangling pointers:
 *   gcc -fsanitize=address -g program.c -o program
 *
 * Run with Valgrind:
 *   valgrind --leak-check=full ./program
 */

#include <stdio.h>
#include <stdlib.h>

#define SAFE_FREE(p) do { free(p); (p) = NULL; } while(0)

int main(void) {
    int *p = (int *)malloc(sizeof(int));
    *p = 42;
    SAFE_FREE(p);          /* free and set to NULL */
    if (p == NULL)
        printf("safely nulled\n");
    /* Compile with: gcc -fsanitize=address to detect use-after-free */
    return 0;
}
